// Elog code 90543 (domain 9/Safety) = "Cyclic Brake Check needs to be done".
// This only tells us whether that warning has been LOGGED recently - the
// safety controller appears to (re-)log it at controller/RAPID start, not
// continuously - see the Limitation comment on this canvas.
function toDate(ts) { return new Date(String(ts).replace(' T ', 'T')); }
var entries = (msg.payload && msg.payload.entries) || [];
var matches = entries.filter(function(e) { return e.code === '90543'; });
matches.sort(function(a, b) { return toDate(b.tstamp) - toDate(a.tstamp); });
var last = matches[0] || null;
msg.payload = {
    ok: true,
    warningLogged: !!last,
    lastWarning: last,
    checkedAt: new Date().toISOString()
};
return msg;

var entry = msg.payload && msg.payload.entry;
if (!entry || entry.code !== '90543') return null;
return msg;
